-- ===================================================
-- migration_041: 板橋 車番→班マスタ（vehicle_teams）
-- 出典: 営業所掲示の「班・ドアNO一覧」写真（2026-07-19読取・379台）
-- 課は班から導出: 1,2班=1課 / 3,4班=2課 / 5,6班=3課 / 7,8班=4課
-- 検証: 車両マスタの課と220台照合で不一致0、乗務実績の班と361/375一致
-- ===================================================

CREATE TABLE IF NOT EXISTS vehicle_teams (
  car_no TEXT PRIMARY KEY,          -- ドアNO（無線番号ではない）
  team   INTEGER NOT NULL CHECK(team BETWEEN 1 AND 8)
);

